# --- Caching Decorator ---
def cache_with_memcached(key_prefix, ttl=300):
    """
    A decorator to cache function results in Memcached.

    Args:
        key_prefix (str): A prefix for the Memcached key.
        ttl (int): Time-to-live for the cache entry in seconds.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name, args, and kwargs
            # For simplicity, we'll just use the first arg if available, otherwise a generic key
            # In a real app, you might use a more robust key generation (e.g., hashlib for args)
            if args:
                cache_key = f"{key_prefix}:{func.__name__}:{args[0]}"
            else:
                cache_key = f"{key_prefix}:{func.__name__}:all"

            # Try to get data from cache
            cached_data = memcached_client.get(cache_key)

            if cached_data:
                app.logger.info(f"Cache HIT for key: {cache_key}")
                # pymemcache returns bytes, decode if necessary
                return eval(cached_data.decode('utf-8')) # Using eval for simplicity, consider json.loads for safety
            else:
                app.logger.info(f"Cache MISS for key: {cache_key}. Fetching from origin.")
                # If not in cache, call the original function
                result = func(*args, **kwargs)

                # Store the result in cache
                # pymemcache expects bytes, so encode the string representation
                memcached_client.set(cache_key, str(result).encode('utf-8'), expire=ttl)
                return result
        return wrapper
    return decorator

